import type { VercelRequest, VercelResponse } from '@vercel/node';
import { createClient } from '@supabase/supabase-js';
import { Database } from '../src/types/database';
import { IntegrationSettings, ServicePackage, SubscriptionPlan } from '../src/types';
import { stripe } from './_shared';

export default async function handler(req: VercelRequest, res: VercelResponse) {
    const supabaseUrl = process.env.VITE_SUPABASE_URL;
    const supabaseServiceKey = process.env.SUPABASE_SERVICE_KEY;
    const frontendUrl = process.env.FRONTEND_URL || req.headers.origin;

    if (!supabaseUrl || !supabaseServiceKey) {
        return res.status(500).json({ error: 'Configuração do servidor incompleta.' });
    }

    const supabaseAdmin = createClient<Database>(supabaseUrl, supabaseServiceKey);

    if (req.method !== 'POST') {
        res.setHeader('Allow', 'POST');
        return res.status(405).end('Method Not Allowed');
    }

    const { appointmentData, packageData } = req.body;

    // Helper para gerar URLs de redirecionamento
    const buildSuccessUrl = (path: string) => {
        const baseUrl = `${frontendUrl}/#${path}`;
        const separator = baseUrl.includes('?') ? '&' : '?';
        return `${baseUrl}${separator}payment_status=success`;
    };

    const buildCancelUrl = (path: string) => {
        const baseUrl = `${frontendUrl}/#${path}`;
        const separator = baseUrl.includes('?') ? '&' : '?';
        return `${baseUrl}${separator}payment_status=failure`;
    };

    try {
        let session;
        let connectedAccountId;

        if (packageData) {
            // Lógica para Pacotes e Assinaturas (Barbearia vendendo para cliente)
            const { type, itemId, barbershopId, userId, userEmail } = packageData;

            const { data: barbershop, error } = await supabaseAdmin
                .from('barbershops')
                .select('integrations, name, packages, subscriptions, slug')
                .eq('id', barbershopId)
                .single();

            if (error || !barbershop) throw new Error('Barbearia não encontrada.');

            const integrations = barbershop.integrations as IntegrationSettings;
            connectedAccountId = integrations?.stripeAccountId;

            if (!connectedAccountId || !integrations.stripeAccountOnboarded) {
                return res.status(400).json({ error: 'Barbearia não conectada ao Stripe.' });
            }

            let itemDetails;
            if (type === 'package') {
                const packages = (barbershop.packages as ServicePackage[]) || [];
                itemDetails = packages.find(p => p.id === itemId);
            } else {
                const subscriptions = (barbershop.subscriptions as SubscriptionPlan[]) || [];
                itemDetails = subscriptions.find(s => s.id === itemId);
            }

            if (!itemDetails) {
                return res.status(404).json({ error: 'Item não encontrado.' });
            }

            const returnPath = barbershop.slug ? `/${barbershop.slug}` : `/?barbershopId=${barbershopId}`;

            session = await stripe.checkout.sessions.create({
                payment_method_types: ['card'],
                line_items: [{
                    price_data: {
                        currency: 'brl',
                        product_data: {
                            name: `${type === 'package' ? 'Pacote' : 'Assinatura'}: ${itemDetails.name}`,
                            description: `Compra na ${barbershop.name}`,
                        },
                        unit_amount: Math.round(itemDetails.price * 100), // Stripe usa centavos
                    },
                    quantity: 1,
                }],
                mode: 'payment',
                success_url: buildSuccessUrl(returnPath),
                cancel_url: buildCancelUrl(returnPath),
                customer_email: userEmail,
                payment_intent_data: {
                    application_fee_amount: Math.round(itemDetails.price * 100 * 0.05), // Ex: 5% de taxa da plataforma
                    transfer_data: {
                        destination: connectedAccountId,
                    },
                },
                metadata: {
                    purchase_type: type,
                    user_id: userId,
                    barbershop_id: barbershopId,
                    item_id: itemId
                },
            });

        } else if (appointmentData) {
            // Lógica para Agendamentos (Barbearia vendendo serviço)
            const { barbershop_id, service_name, price, client_name, barber_name, service_id, client_id, start_time, end_time } = appointmentData;

            const { data: barbershop, error } = await supabaseAdmin
                .from('barbershops')
                .select('integrations, name, slug')
                .eq('id', barbershop_id)
                .single();

            if (error || !barbershop) throw new Error('Barbearia não encontrada.');

            const integrations = barbershop.integrations as IntegrationSettings;
            connectedAccountId = integrations?.stripeAccountId;

            if (!connectedAccountId || !integrations.stripeAccountOnboarded) {
                return res.status(400).json({ error: 'Barbearia não conectada ao Stripe.' });
            }

            const returnPath = barbershop.slug ? `/${barbershop.slug}` : `/?barbershopId=${barbershop_id}`;

            session = await stripe.checkout.sessions.create({
                payment_method_types: ['card'],
                line_items: [{
                    price_data: {
                        currency: 'brl',
                        product_data: {
                            name: `Agendamento: ${service_name}`,
                            description: `${barber_name} - ${new Date(start_time).toLocaleString('pt-BR')}`,
                        },
                        unit_amount: Math.round(price * 100),
                    },
                    quantity: 1,
                }],
                mode: 'payment',
                success_url: buildSuccessUrl(returnPath),
                cancel_url: buildCancelUrl(returnPath),
                payment_intent_data: {
                    application_fee_amount: Math.round(price * 100 * 0.02), // Ex: 2% de taxa da plataforma em agendamentos
                    transfer_data: {
                        destination: connectedAccountId,
                    },
                },
                metadata: {
                    purchase_type: 'appointment',
                    barbershop_id,
                    client_id,
                    service_id,
                    barber_name,
                    client_name,
                    start_time,
                    end_time,
                    price: price.toString(),
                    service_name
                },
            });
        }

        if (!session) throw new Error('Falha ao criar sessão de checkout.');

        res.status(200).json({ url: session.url });

    } catch (error: any) {
        console.error('Erro Stripe Checkout:', error);
        res.status(500).json({ error: error.message });
    }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { stripe, PLANS } from './_shared';

export default async function handler(req: VercelRequest, res: VercelResponse) {
    const frontendUrl = process.env.FRONTEND_URL || req.headers.origin;

    if (req.method !== 'POST') {
        res.setHeader('Allow', 'POST');
        return res.status(405).end('Method Not Allowed');
    }

    const { planId, billingCycle, barbershopId } = req.body;
    const plan = PLANS.find(p => p.id === planId);

    if (!plan || !billingCycle || !barbershopId) {
        return res.status(400).json({ error: 'Dados incompletos.' });
    }

    try {
        const price = billingCycle === 'annual' ? plan.priceAnnual : plan.priceMonthly;
        const productName = `Plano ${plan.name} (${billingCycle === 'annual' ? 'Anual' : 'Mensal'})`;

        // Para simplificar, estamos criando um pagamento único recorrente.
        // Em um cenário real de SaaS, você criaria Products e Prices no Stripe e usaria seus IDs.
        // Aqui usaremos price_data ad-hoc para criar a assinatura/pagamento.

        const session = await stripe.checkout.sessions.create({
            payment_method_types: ['card'],
            line_items: [{
                price_data: {
                    currency: 'brl',
                    product_data: {
                        name: productName,
                        description: 'Assinatura BarberAI',
                    },
                    unit_amount: Math.round(price * 100),
                    // Se quiser assinatura real recorrente, descomente:
                    // recurring: { interval: billingCycle === 'annual' ? 'year' : 'month' }, 
                },
                quantity: 1,
            }],
            mode: 'payment', // Use 'subscription' se ativar recurring acima
            success_url: `${frontendUrl}/#settings?payment_status=success`,
            cancel_url: `${frontendUrl}/#settings?payment_status=failure`,
            metadata: {
                purchase_type: 'plan_subscription',
                plan_id: planId,
                billing_cycle: billingCycle,
                barbershop_id: barbershopId
            },
        });

        res.status(200).json({ url: session.url });

    } catch (error: any) {
        console.error('Erro Stripe Plan Checkout:', error);
        res.status(500).json({ error: error.message });
    }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { stripe } from './_shared';

export default async function handler(req: VercelRequest, res: VercelResponse) {
    const frontendUrl = process.env.FRONTEND_URL || req.headers.origin;
    const clientId = process.env.STRIPE_CLIENT_ID;

    if (!clientId) {
        return res.status(500).json({ error: 'STRIPE_CLIENT_ID não configurado.' });
    }

    if (req.method !== 'POST') {
        return res.status(405).end('Method Not Allowed');
    }

    const { barbershopId } = req.body;
    if (!barbershopId) {
        return res.status(400).json({ error: 'Barbershop ID required.' });
    }

    // URL para onde o usuário será redirecionado após o onboarding no Stripe
    const redirectUri = `${frontendUrl}/api/stripe-callback`;

    // Gerar link OAuth do Stripe Express/Standard
    // state: usamos para passar o ID da barbearia de volta com segurança
    const url = `https://connect.stripe.com/oauth/authorize?response_type=code&client_id=${clientId}&scope=read_write&redirect_uri=${redirectUri}&state=${barbershopId}`;

    res.status(200).json({ url });
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { createClient } from '@supabase/supabase-js';
import { Database } from '../src/types/database';
import { stripe } from './_shared';
import { IntegrationSettings, Json } from '../src/types';

export default async function handler(req: VercelRequest, res: VercelResponse) {
    const frontendUrl = process.env.FRONTEND_URL || `https://${req.headers.host}`;
    const supabaseAdmin = createClient<Database>(process.env.VITE_SUPABASE_URL!, process.env.SUPABASE_SERVICE_KEY!);

    const { code, state } = req.query; // 'state' contém o barbershopId

    if (!code || !state) {
        return res.status(400).send('Código ou estado ausente.');
    }

    const barbershopId = state as string;

    try {
        // 1. Trocar o código de autorização pelo ID da conta conectada
        const response = await stripe.oauth.token({
            grant_type: 'authorization_code',
            code: code as string,
        });

        const connectedAccountId = response.stripe_user_id;

        // 2. Buscar configurações atuais
        const { data: barbershop, error: fetchError } = await supabaseAdmin
            .from('barbershops')
            .select('integrations')
            .eq('id', barbershopId)
            .single();

        if (fetchError) throw fetchError;

        const currentIntegrations = (barbershop.integrations as IntegrationSettings) || {};

        // 3. Atualizar configurações com o ID do Stripe
        const updatedIntegrations: IntegrationSettings = {
            ...currentIntegrations,
            stripeAccountId: connectedAccountId,
            stripeAccountOnboarded: true,
        };

        const { error: updateError } = await supabaseAdmin
            .from('barbershops')
            .update({ integrations: updatedIntegrations as Json })
            .eq('id', barbershopId);

        if (updateError) throw updateError;

        // 4. Redirecionar de volta para o painel
        res.redirect(302, `${frontendUrl}/#settings`);

    } catch (error: any) {
        console.error('Stripe Connect Callback Error:', error);
        res.status(500).send(`Erro ao conectar conta Stripe: ${error.message}`);
    }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { createClient } from '@supabase/supabase-js';
import { Database } from '../src/types/database';
import { IntegrationSettings, Json } from '../src/types';

export default async function handler(req: VercelRequest, res: VercelResponse) {
    const supabaseAdmin = createClient<Database>(process.env.VITE_SUPABASE_URL!, process.env.SUPABASE_SERVICE_KEY!);

    if (req.method !== 'POST') return res.status(405).end();

    const { barbershopId } = req.body;

    try {
        const { data: barbershop } = await supabaseAdmin
            .from('barbershops')
            .select('integrations')
            .eq('id', barbershopId)
            .single();

        const currentIntegrations = (barbershop?.integrations as IntegrationSettings) || {};

        // Remover campos do Stripe
        const { stripeAccountId, stripeAccountOnboarded, ...rest } = currentIntegrations;

        await supabaseAdmin
            .from('barbershops')
            .update({ integrations: rest as Json })
            .eq('id', barbershopId);

        res.status(200).json({ success: true });
    } catch (error: any) {
        res.status(500).json({ error: error.message });
    }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { createClient } from '@supabase/supabase-js';
import { Database, TablesInsert, Json } from '../src/types/database';
import { IntegrationSettings, ServicePackage, UserActiveSubscription, UserPurchasedPackage } from '../src/types';
import { stripe } from './_shared';
import { buffer } from 'micro';
import { randomUUID } from 'crypto';

const supabaseAdmin = createClient<Database>(process.env.VITE_SUPABASE_URL!, process.env.SUPABASE_SERVICE_KEY!);

// Desativar body parsing automático do Vercel para validar assinatura
export const config = {
  api: {
    bodyParser: false,
  },
};

export default async function handler(req: VercelRequest, res: VercelResponse) {
    if (req.method !== 'POST') return res.status(405).end();

    const buf = await buffer(req);
    const sig = req.headers['stripe-signature']!;
    let event;

    try {
        event = stripe.webhooks.constructEvent(buf, sig, process.env.STRIPE_WEBHOOK_SECRET!);
    } catch (err: any) {
        console.error(`Webhook signature verification failed: ${err.message}`);
        return res.status(400).send(`Webhook Error: ${err.message}`);
    }

    if (event.type === 'checkout.session.completed') {
        const session = event.data.object as any;
        const metadata = session.metadata;

        console.log('Processing checkout session:', session.id, metadata);

        try {
            if (metadata.purchase_type === 'plan_subscription') {
                // Pagamento de Assinatura da Plataforma (Barbearia pagando o SaaS)
                await handlePlanPayment(metadata);
            } else if (metadata.purchase_type === 'appointment') {
                // Pagamento de Agendamento (Cliente pagando Barbearia)
                await handleAppointmentPayment(metadata, session.id);
            } else if (metadata.purchase_type === 'package' || metadata.purchase_type === 'subscription') {
                // Compra de Pacote/Assinatura de Serviços (Cliente comprando da Barbearia)
                await handleItemPurchase(metadata);
            }
        } catch (error) {
            console.error('Error processing webhook logic:', error);
            return res.status(500).send('Internal Server Error');
        }
    }

    res.status(200).json({ received: true });
}

async function handlePlanPayment(metadata: any) {
    const { barbershop_id, plan_id, billing_cycle } = metadata;

    const { data: barbershop } = await supabaseAdmin.from('barbershops').select('integrations').eq('id', barbershop_id).single();
    if (!barbershop) return;

    const currentIntegrations = (barbershop.integrations as IntegrationSettings) || {};
    const newExpiryDate = new Date();

    if (billing_cycle === 'annual') {
        newExpiryDate.setFullYear(newExpiryDate.getFullYear() + 1);
    } else {
        newExpiryDate.setMonth(newExpiryDate.getMonth() + 1);
    }

    const updatedIntegrations = {
        ...currentIntegrations,
        plan: plan_id,
        plan_type: billing_cycle,
        plan_expires_at: newExpiryDate.toISOString(),
        plan_status: 'active',
    };

