    }
    return await response.json();
};

export const createPackageSubscriptionCheckout = async (type: 'package' | 'subscription', itemId: string, barbershopId: string, user: User): Promise<{ url: string }> => {
    const response = await fetch(`/api/create-stripe-checkout`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ packageData: { type, itemId, barbershopId, userId: user.id, userEmail: user.email } }),
    });
    if (!response.ok) {
        const errorBody = await response.json();
        throw new Error(errorBody.error || 'Falha ao criar sessão de pagamento.');
    }
    return await response.json();
};

export const createPlanCheckoutSession = async (planId: string, billingCycle: 'monthly' | 'annual', barbershopId: string): Promise<{ url: string }> => {
    const response = await fetch(`/api/create-plan-checkout`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ planId, billingCycle, barbershopId }),
    });
    if (!response.ok) {
        const errorBody = await response.json();
        throw new Error(errorBody.error || 'Falha ao criar sessão de assinatura.');
    }
    return await response.json();
};

export const connectStripeAccount = async (barbershopId: string): Promise<void> => {
    const response = await fetch('/api/stripe-connect', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ barbershopId }),
    });

    if (!response.ok) {
        const errorBody = await response.json();
        throw new Error(errorBody.error || 'Falha ao iniciar conexão com Stripe.');
    }

    const { url } = await response.json();
    window.location.href = url;
};

export const disconnectStripeAccount = async (barbershopId: string): Promise<void> => {
    const response = await fetch('/api/stripe-disconnect', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ barbershopId }),
    });

    if (!response.ok) {
        const errorBody = await response.json();
        throw new Error(errorBody.error || 'Falha ao desconectar Stripe.');
    }
};

